import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic3x3() {
        int[][] matrix = {
            {1, 2, 3},
            {4, 5, 6},
            {7, 8, 9}
        };
        new Solution().rotate(matrix);
        assertArrayEquals(new int[][]{
            {7, 4, 1},
            {8, 5, 2},
            {9, 6, 3}
        }, matrix);
    }

    @Test
    void twoByTwo() {
        int[][] matrix = {
            {1, 2},
            {3, 4}
        };
        new Solution().rotate(matrix);
        assertArrayEquals(new int[][]{
            {3, 1},
            {4, 2}
        }, matrix);
    }

    @Test
    void singleCell() {
        int[][] matrix = {{42}};
        new Solution().rotate(matrix);
        assertArrayEquals(new int[][]{{42}}, matrix);
    }

    @Test
    void emptyMatrix() {
        int[][] matrix = {};
        new Solution().rotate(matrix); // must not throw
        assertEquals(0, matrix.length);
    }

    @Test
    void fourByFour() {
        int[][] matrix = {
            { 5,  1,  9, 11},
            { 2,  4,  8, 10},
            {13,  3,  6,  7},
            {15, 14, 12, 16}
        };
        new Solution().rotate(matrix);
        assertArrayEquals(new int[][]{
            {15, 13,  2,  5},
            {14,  3,  4,  1},
            {12,  6,  8,  9},
            {16,  7, 10, 11}
        }, matrix);
    }

    @Test
    void allZeros() {
        int[][] matrix = {
            {0, 0, 0},
            {0, 0, 0},
            {0, 0, 0}
        };
        new Solution().rotate(matrix);
        assertArrayEquals(new int[][]{
            {0, 0, 0},
            {0, 0, 0},
            {0, 0, 0}
        }, matrix);
    }

    @Test
    void rotateFullCircle() {
        // Rotating 4 times must return to the original
        int[][] matrix = {
            {1, 2, 3},
            {4, 5, 6},
            {7, 8, 9}
        };
        int[][] original = {
            {1, 2, 3},
            {4, 5, 6},
            {7, 8, 9}
        };
        Solution s = new Solution();
        s.rotate(matrix);
        s.rotate(matrix);
        s.rotate(matrix);
        s.rotate(matrix);
        assertArrayEquals(original, matrix);
    }
}
